def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_factor = np.log1p(cap + item)
        complexity = 0.0
        decay = 1.0
        bonus = 0.0
        penalty = 0.0
        threshold = item / max(cap, 1e-9)
        for m in range(2, 17):
            if m % 4 == 0:
                complexity += np.tanh(threshold * m) * (m ** 1.5) / (cap + 1)
            elif m % 3 == 0:
                complexity -= np.cosh(threshold / (m + 1)) / (m + 2)
            else:
                complexity += np.log1p(m * threshold) / (np.sqrt(m) + 0.1)
            if (cap + m) % 5 == 0:
                decay *= 0.97 + 0.01 * m
            elif (cap * m) % 4 == 0:
                decay *= 1.03 - 0.005 * m
            if m == 12:
                for n in range(1, 8):
                    value = cap - item * (n ** 3)
                    if value > 0:
                        if value % (n + 3) == 0:
                            bonus += np.power(value, 0.7) / (n + 4)
                        else:
                            bonus -= np.log1p(abs(value)) / (n + 5)
                    else:
                        penalty += np.abs(value)**1.4 / (n + 6)
            if threshold > 0.9 and m % 2 == 1:
                decay *= 1.05 + 0.015 * m
            elif threshold < 0.15 and m % 5 == 2:
                decay *= 0.85 - 0.02 * m
        adjusted_score = (complexity + bonus - penalty) * decay
        if adjusted_score < 0:
            priorities[i] = -adjusted_score * base_factor / (np.sqrt(cap) + 1)
        else:
            if cap > item * 3:
                priorities[i] = -adjusted_score * (1 + threshold) / (cap + 2)
            else:
                priorities[i] = -adjusted_score * np.exp(-threshold**3) / (np.cbrt(cap) + 1)
        if cap % 3 == 0:
            priorities[i] *= 1.07
        elif cap % 5 == 0:
            priorities[i] *= 0.93
        if threshold > 1.0:
            priorities[i] += np.sin(cap * threshold) * 0.2
        elif threshold < 0.1:
            priorities[i] -= np.cos(cap + item) * 0.1
        if (item + cap) % 2 == 0:
            priorities[i] *= 0.99
        else:
            priorities[i] *= 1.01
    return priorities
